{
  "$defs": {
    "CalendarEvent": {
      "description": "A single calendar event extracted from an email.",
      "properties": {
        "title": {
          "description": "The event title or name",
          "title": "Title",
          "type": "string"
        },
        "start_datetime": {
          "anyOf": [
            {
              "format": "date-time",
              "type": "string"
            },
            {
              "type": "null"
            }
          ],
          "default": null,
          "description": "Local wall-clock start in the user's timezone as naive ISO 8601 (e.g. 2026-09-13T10:00:00). Do not include Z or numeric offsets.",
          "title": "Start Datetime"
        },
        "end_datetime": {
          "anyOf": [
            {
              "format": "date-time",
              "type": "string"
            },
            {
              "type": "null"
            }
          ],
          "default": null,
          "description": "Local wall-clock end in the user's timezone as naive ISO 8601 (e.g. 2026-09-13T14:00:00). Do not include Z or numeric offsets.",
          "title": "End Datetime"
        },
        "all_day": {
          "default": false,
          "description": "Whether this is an all-day event",
          "title": "All Day",
          "type": "boolean"
        },
        "location": {
          "anyOf": [
            {
              "type": "string"
            },
            {
              "type": "null"
            }
          ],
          "default": null,
          "description": "The event location or venue",
          "title": "Location"
        },
        "description": {
          "description": "Detailed description of the event with all relevant information",
          "title": "Description",
          "type": "string"
        },
        "importance": {
          "default": "action_required",
          "description": "Event importance: 'action_required' for closures, schedule changes, deadlines the user must act on; 'fyi' for themed days, birthdays, informational items that are nice to know",
          "enum": [
            "action_required",
            "fyi"
          ],
          "title": "Importance",
          "type": "string"
        },
        "recurrence_rule": {
          "anyOf": [
            {
              "type": "string"
            },
            {
              "type": "null"
            }
          ],
          "default": null,
          "description": "RFC 5545 RRULE for recurring events (e.g., 'RRULE:FREQ=WEEKLY;BYDAY=MO'). Null for one-time events.",
          "title": "Recurrence Rule"
        }
      },
      "required": [
        "title",
        "description"
      ],
      "title": "CalendarEvent",
      "type": "object"
    }
  },
  "description": "LLM response containing extracted events.",
  "properties": {
    "events_found": {
      "description": "Whether any calendar events were found in the email",
      "title": "Events Found",
      "type": "boolean"
    },
    "events": {
      "description": "List of extracted calendar events",
      "items": {
        "$ref": "#/$defs/CalendarEvent"
      },
      "title": "Events",
      "type": "array"
    }
  },
  "required": [
    "events_found"
  ],
  "title": "EventExtractionResponse",
  "type": "object"
}
